// ==UserScript==
// @name         n8n AI Workflow Creator
// @namespace    https://n8n.marlonai.net.pe
// @version      2.0.0
// @description  Chat flotante para crear workflows con IA
// @match        https://n8n.marlonai.net.pe/*
// @grant        GM_addStyle
// @grant        GM_setValue
// @grant        GM_getValue
// @run-at       document-idle
// ==/UserScript==

(function () {
  'use strict';

  // Embedded icon — do not edit this line manually
  const ICON = 'data:image/png;base64,';

  // ─────────────────────────────────────────────────────────────────────────
  // CONFIG
  // ─────────────────────────────────────────────────────────────────────────
  const CONFIG = {
    WEBHOOK_URL:    'https://hooks.marlonai.net.pe/webhook/create-workflow',
    AI_TOKEN:       '9ae58ecfe00d462cbdbc5fb9d4a449376f688b374193b5c7f720beeb18a7e3fe',
    N8N_EDITOR_URL: 'https://n8n.marlonai.net.pe',
    MODELS: [
      { id: 'ollama', name: 'Ollama — Local',      default: true },
      { id: 'claude', name: 'Claude — Anthropic' },
      { id: 'gpt',    name: 'GPT — OpenAI' },
    ],
  };

  // ─────────────────────────────────────────────────────────────────────────
  // CSS
  // ─────────────────────────────────────────────────────────────────────────
  GM_addStyle(`
    /* ── FAB ─────────────────────────────────────────── */
    #n8n-ai-fab {
      position: fixed;
      bottom: 24px;
      right: 24px;
      width: 52px;
      height: 52px;
      border-radius: 50%;
      background: #ffffff;
      border: none;
      cursor: pointer;
      z-index: 99999;
      padding: 0;
      overflow: hidden;
      display: flex;
      align-items: center;
      justify-content: center;
      box-shadow: 0 4px 14px rgba(0,0,0,0.22), 0 1px 4px rgba(0,0,0,0.12);
      transition: transform 0.18s ease, box-shadow 0.18s ease;
    }
    #n8n-ai-fab:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 24px rgba(0,0,0,0.28), 0 2px 8px rgba(0,0,0,0.15);
    }
    #n8n-ai-fab:active { transform: scale(0.94); }
    #n8n-ai-fab img {
      width: 44px;
      height: 44px;
      object-fit: cover;
      display: block;
    }

    /* ── Widget ───────────────────────────────────────── */
    #n8n-ai-widget {
      position: fixed;
      bottom: 88px;
      right: 24px;
      width: 360px;
      height: 520px;
      background: #0f0f0f;
      border: 1px solid rgba(255,255,255,0.07);
      border-radius: 16px;
      box-shadow: 0 24px 60px rgba(0,0,0,0.65), 0 0 0 1px rgba(255,255,255,0.03);
      z-index: 99999;
      display: flex;
      flex-direction: column;
      overflow: hidden;
      opacity: 0;
      transform: translateY(10px) scale(0.98);
      pointer-events: none;
      transition: opacity 0.2s ease, transform 0.2s ease;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      font-size: 13px;
      color: #ededed;
    }
    #n8n-ai-widget.n8n-ai-visible {
      opacity: 1;
      transform: translateY(0) scale(1);
      pointer-events: all;
    }

    /* ── Header ───────────────────────────────────────── */
    #n8n-ai-header {
      background: #1a1a1a;
      padding: 12px 14px;
      display: flex;
      align-items: center;
      gap: 10px;
      cursor: grab;
      user-select: none;
      flex-shrink: 0;
      border-bottom: 1px solid rgba(255,255,255,0.05);
    }
    #n8n-ai-header:active { cursor: grabbing; }
    #n8n-ai-avatar {
      width: 30px;
      height: 30px;
      border-radius: 50%;
      overflow: hidden;
      flex-shrink: 0;
      background: #fff;
    }
    #n8n-ai-avatar img {
      width: 30px;
      height: 30px;
      object-fit: cover;
      display: block;
    }
    #n8n-ai-header-text {
      flex: 1;
      display: flex;
      flex-direction: column;
      gap: 1px;
      min-width: 0;
    }
    #n8n-ai-title {
      font-size: 13px;
      font-weight: 600;
      color: #f2f2f2;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    #n8n-ai-subtitle {
      font-size: 10.5px;
      color: #555;
      font-weight: 400;
    }
    #n8n-ai-sdot {
      width: 7px;
      height: 7px;
      border-radius: 50%;
      background: #333;
      flex-shrink: 0;
      transition: background 0.4s ease;
    }
    #n8n-ai-sdot.n8n-ai-sdot-online  { background: #4caf50; }
    #n8n-ai-sdot.n8n-ai-sdot-offline { background: #444; }
    #n8n-ai-sdot.n8n-ai-sdot-error   { background: #e53935; }
    .n8n-ai-hbtn {
      background: transparent;
      border: none;
      color: #4a4a4a;
      cursor: pointer;
      width: 26px;
      height: 26px;
      border-radius: 6px;
      font-size: 15px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      transition: background 0.15s, color 0.15s;
    }
    .n8n-ai-hbtn:hover { background: rgba(255,255,255,0.06); color: #bbb; }

    /* ── Model bar ────────────────────────────────────── */
    #n8n-ai-model-bar {
      padding: 7px 14px;
      background: #1a1a1a;
      border-bottom: 1px solid rgba(255,255,255,0.05);
      flex-shrink: 0;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    #n8n-ai-model-label {
      font-size: 10.5px;
      color: #444;
      font-weight: 600;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      flex-shrink: 0;
    }
    #n8n-ai-model {
      flex: 1;
      background: #222;
      border: 1px solid rgba(255,255,255,0.07);
      color: #aaa;
      border-radius: 7px;
      padding: 4px 8px;
      font-size: 12px;
      cursor: pointer;
      outline: none;
      font-family: inherit;
      transition: border-color 0.15s, color 0.15s;
    }
    #n8n-ai-model:hover { color: #ccc; }
    #n8n-ai-model:focus { border-color: rgba(229,57,53,0.35); color: #ddd; }

    /* ── Chat area ────────────────────────────────────── */
    #n8n-ai-chat {
      flex: 1;
      overflow-y: auto;
      padding: 16px 14px;
      display: flex;
      flex-direction: column;
      gap: 10px;
      scroll-behavior: smooth;
    }
    #n8n-ai-chat::-webkit-scrollbar { width: 3px; }
    #n8n-ai-chat::-webkit-scrollbar-track { background: transparent; }
    #n8n-ai-chat::-webkit-scrollbar-thumb {
      background: rgba(255,255,255,0.08);
      border-radius: 2px;
    }

    /* ── Messages ─────────────────────────────────────── */
    .n8n-ai-msg {
      max-width: 85%;
      padding: 9px 12px;
      border-radius: 12px;
      line-height: 1.5;
      word-break: break-word;
      font-size: 12.5px;
      white-space: pre-wrap;
    }
    .n8n-ai-user {
      background: #e53935;
      align-self: flex-end;
      border-bottom-right-radius: 3px;
      color: #fff;
    }
    .n8n-ai-ai {
      background: #1a1a1a;
      border: 1px solid rgba(255,255,255,0.06);
      align-self: flex-start;
      border-bottom-left-radius: 3px;
      color: #ccc;
    }
    .n8n-ai-system {
      align-self: center;
      text-align: center;
      color: #3a3a3a;
      font-size: 11.5px;
      max-width: 100%;
      background: transparent;
    }
    .n8n-ai-success {
      background: rgba(76,175,80,0.07) !important;
      border-color: rgba(76,175,80,0.18) !important;
      color: #ccc !important;
    }
    .n8n-ai-success-label {
      font-size: 10px;
      text-transform: uppercase;
      letter-spacing: 0.07em;
      color: #4caf50;
      font-weight: 700;
      margin-bottom: 3px;
    }
    .n8n-ai-success-name {
      color: #f0f0f0;
      font-weight: 500;
      font-size: 13px;
      margin-bottom: 7px;
    }
    .n8n-ai-error {
      background: rgba(229,57,53,0.07) !important;
      border-color: rgba(229,57,53,0.16) !important;
      color: #e57373 !important;
    }
    .n8n-ai-wf-link {
      display: inline-flex;
      align-items: center;
      gap: 3px;
      color: #4caf50;
      text-decoration: none;
      font-size: 12px;
      font-weight: 500;
      letter-spacing: 0.01em;
    }
    .n8n-ai-wf-link:hover { text-decoration: underline; }

    /* ── Thinking dots ────────────────────────────────── */
    .n8n-ai-thinking {
      display: flex;
      gap: 4px;
      align-items: center;
      padding: 2px 0;
    }
    .n8n-ai-dot {
      width: 5px;
      height: 5px;
      border-radius: 50%;
      background: #3a3a3a;
      animation: n8n-ai-bounce 1.4s ease-in-out infinite;
    }
    .n8n-ai-dot:nth-child(2) { animation-delay: 0.18s; }
    .n8n-ai-dot:nth-child(3) { animation-delay: 0.36s; }
    @keyframes n8n-ai-bounce {
      0%, 60%, 100% { transform: translateY(0);   opacity: 0.4; }
      30%            { transform: translateY(-5px); opacity: 1;   }
    }

    /* ── Input area ───────────────────────────────────── */
    #n8n-ai-input-area {
      padding: 10px 12px;
      background: #1a1a1a;
      border-top: 1px solid rgba(255,255,255,0.05);
      display: flex;
      gap: 8px;
      align-items: flex-end;
      flex-shrink: 0;
    }
    #n8n-ai-textarea {
      flex: 1;
      background: #222;
      border: 1px solid rgba(255,255,255,0.07);
      color: #ededed;
      border-radius: 10px;
      padding: 9px 12px;
      font-size: 12.5px;
      font-family: inherit;
      resize: none;
      outline: none;
      min-height: 38px;
      max-height: 90px;
      overflow-y: auto;
      line-height: 1.45;
      transition: border-color 0.15s;
    }
    #n8n-ai-textarea:focus { border-color: rgba(229,57,53,0.38); }
    #n8n-ai-textarea::placeholder { color: #333; }
    #n8n-ai-send {
      background: #e53935;
      border: none;
      color: #fff;
      width: 36px;
      height: 36px;
      border-radius: 10px;
      cursor: pointer;
      font-size: 14px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      transition: background 0.15s, transform 0.1s;
    }
    #n8n-ai-send:hover  { background: #c62828; }
    #n8n-ai-send:active { transform: scale(0.91); }
    #n8n-ai-send:disabled { background: #1f1f1f; opacity: 0.45; cursor: not-allowed; }
  `);

  // ─────────────────────────────────────────────────────────────────────────
  // STATE
  // ─────────────────────────────────────────────────────────────────────────
  let isOpen     = false;
  let isDragging = false;
  let isSending  = false;
  let dragOffset = { x: 0, y: 0 };

  let $fab, $widget, $chat, $textarea, $send, $statusDot;

  // ─────────────────────────────────────────────────────────────────────────
  // HTML
  // ─────────────────────────────────────────────────────────────────────────
  function buildHTML() {
    const fab = document.createElement('button');
    fab.id    = 'n8n-ai-fab';
    fab.title = 'Workflow Creator  (Ctrl+Shift+A)';
    fab.innerHTML = `<img src="${ICON}" alt="Workflow Creator" />`;

    const widget = document.createElement('div');
    widget.id = 'n8n-ai-widget';
    widget.innerHTML = `
      <div id="n8n-ai-header">
        <div id="n8n-ai-avatar"><img src="${ICON}" alt="" /></div>
        <div id="n8n-ai-header-text">
          <span id="n8n-ai-title">Workflow Creator</span>
          <span id="n8n-ai-subtitle">n8n · AI-powered</span>
        </div>
        <span id="n8n-ai-sdot" class="n8n-ai-sdot n8n-ai-sdot-offline" title="Estado del servidor"></span>
        <button class="n8n-ai-hbtn" id="n8n-ai-minimize" title="Minimizar">&mdash;</button>
        <button class="n8n-ai-hbtn" id="n8n-ai-close"    title="Cerrar">&times;</button>
      </div>
      <div id="n8n-ai-model-bar">
        <span id="n8n-ai-model-label">Modelo</span>
        <select id="n8n-ai-model">${
          CONFIG.MODELS
            .map(m => `<option value="${m.id}"${m.default ? ' selected' : ''}>${m.name}</option>`)
            .join('')
        }</select>
      </div>
      <div id="n8n-ai-chat"></div>
      <div id="n8n-ai-input-area">
        <textarea id="n8n-ai-textarea" placeholder="Describe el workflow..." rows="1"></textarea>
        <button id="n8n-ai-send" title="Enviar (Enter)">&#9658;</button>
      </div>
    `;

    document.body.appendChild(fab);
    document.body.appendChild(widget);
    return { fab, widget };
  }

  // ─────────────────────────────────────────────────────────────────────────
  // VISIBILITY
  // ─────────────────────────────────────────────────────────────────────────
  function openWidget() {
    isOpen = true;
    $widget.classList.add('n8n-ai-visible');
    $fab.style.display = 'none';
    $textarea.focus();
  }

  function closeWidget() {
    isOpen = false;
    $widget.classList.remove('n8n-ai-visible');
    $fab.style.display = 'flex';
  }

  function toggleWidget() {
    isOpen ? closeWidget() : openWidget();
  }

  // ─────────────────────────────────────────────────────────────────────────
  // STATUS DOT
  // ─────────────────────────────────────────────────────────────────────────
  function setStatus(state) {
    $statusDot.className = `n8n-ai-sdot n8n-ai-sdot-${state}`;
  }

  // ─────────────────────────────────────────────────────────────────────────
  // MESSAGES
  // ─────────────────────────────────────────────────────────────────────────
  function addMessage(role, text, options = {}) {
    const div = document.createElement('div');
    div.classList.add('n8n-ai-msg');

    if (options.type === 'loading') {
      div.id = 'n8n-ai-loading';
      div.classList.add('n8n-ai-ai');
      div.innerHTML = `<div class="n8n-ai-thinking">
        <span class="n8n-ai-dot"></span>
        <span class="n8n-ai-dot"></span>
        <span class="n8n-ai-dot"></span>
      </div>`;

    } else if (options.type === 'success') {
      div.classList.add('n8n-ai-ai', 'n8n-ai-success');
      div.innerHTML = `
        <div class="n8n-ai-success-label">Workflow creado</div>
        <div class="n8n-ai-success-name">${options.name || ''}</div>
        ${options.link
          ? `<a href="${options.link}" target="_blank" rel="noopener noreferrer" class="n8n-ai-wf-link">Abrir en editor →</a>`
          : ''}`;

    } else {
      const cls = role === 'user' ? 'n8n-ai-user' : role === 'system' ? 'n8n-ai-system' : 'n8n-ai-ai';
      div.classList.add(cls);
      if (options.type === 'error') div.classList.add('n8n-ai-error');
      div.textContent = text;
    }

    $chat.appendChild(div);
    $chat.scrollTop = $chat.scrollHeight;
    return div;
  }

  function removeLoading() {
    const el = document.getElementById('n8n-ai-loading');
    if (el) el.remove();
  }

  // ─────────────────────────────────────────────────────────────────────────
  // SEND
  // ─────────────────────────────────────────────────────────────────────────
  async function sendMessage() {
    const description = $textarea.value.trim();
    if (!description || isSending) return;

    const model = document.getElementById('n8n-ai-model').value;
    isSending = true;
    $send.disabled = true;
    $textarea.value = '';
    autoResize($textarea);

    addMessage('user', description);
    addMessage('ai', '', { type: 'loading' });

    try {
      const response = await fetch(CONFIG.WEBHOOK_URL, {
        method:  'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-AI-Token':   CONFIG.AI_TOKEN,
        },
        body: JSON.stringify({ model, description }),
      });

      removeLoading();

      if (response.ok) {
        const data = await response.json();
        if (data.success) {
          const name = data.name || 'Sin nombre';
          const link = data.workflow_id
            ? `${CONFIG.N8N_EDITOR_URL}/workflow/${data.workflow_id}`
            : null;
          addMessage('ai', null, { type: 'success', name: `"${name}"`, link });
        } else {
          addMessage('ai', data.error || 'Ocurrió un error inesperado.', { type: 'error' });
        }
      } else {
        const msg = response.status === 403
          ? 'Token inválido — verificá la configuración.'
          : response.status === 502 || response.status === 503
            ? 'El servidor no está disponible.'
            : `Error ${response.status} — intentá de nuevo.`;
        addMessage('ai', msg, { type: 'error' });
      }
    } catch (_) {
      removeLoading();
      addMessage('ai', 'Sin conexión con el servidor. ¿Está Docker corriendo?', { type: 'error' });
    } finally {
      isSending      = false;
      $send.disabled = false;
      $textarea.focus();
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // DRAG
  // ─────────────────────────────────────────────────────────────────────────
  function clamp(v, lo, hi) { return Math.min(Math.max(v, lo), hi); }

  function applyPosition(x, y) {
    const maxX = window.innerWidth  - $widget.offsetWidth;
    const maxY = window.innerHeight - $widget.offsetHeight;
    $widget.style.left   = clamp(x, 0, maxX) + 'px';
    $widget.style.top    = clamp(y, 0, maxY) + 'px';
    $widget.style.right  = 'auto';
    $widget.style.bottom = 'auto';
  }

  function onDragStart(cx, cy) {
    const r   = $widget.getBoundingClientRect();
    dragOffset = { x: cx - r.left, y: cy - r.top };
    isDragging = true;
    document.body.style.userSelect = 'none';
  }

  function onDragMove(cx, cy) {
    if (!isDragging) return;
    applyPosition(cx - dragOffset.x, cy - dragOffset.y);
  }

  async function onDragEnd() {
    if (!isDragging) return;
    isDragging = false;
    document.body.style.userSelect = '';
    const r = $widget.getBoundingClientRect();
    await GM_setValue('widgetPosition', JSON.stringify({ x: r.left, y: r.top }));
  }

  function bindDrag($header) {
    $header.addEventListener('mousedown', e => {
      if (e.target.closest('.n8n-ai-hbtn')) return;
      e.preventDefault();
      onDragStart(e.clientX, e.clientY);
    });
    document.addEventListener('mousemove', e => onDragMove(e.clientX, e.clientY));
    document.addEventListener('mouseup',   ()  => onDragEnd());

    $header.addEventListener('touchstart', e => {
      if (e.target.closest('.n8n-ai-hbtn')) return;
      onDragStart(e.touches[0].clientX, e.touches[0].clientY);
    }, { passive: true });
    document.addEventListener('touchmove', e => {
      if (!isDragging) return;
      onDragMove(e.touches[0].clientX, e.touches[0].clientY);
    }, { passive: true });
    document.addEventListener('touchend', () => onDragEnd());
  }

  async function restorePosition() {
    try {
      const raw = await GM_getValue('widgetPosition', null);
      if (!raw) return;
      const { x, y } = JSON.parse(raw);
      applyPosition(x, y);
    } catch (_) { /* use css default */ }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // HEALTH CHECK
  // ─────────────────────────────────────────────────────────────────────────
  async function checkHealth() {
    setStatus('offline');
    try {
      const res = await fetch(CONFIG.WEBHOOK_URL, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json', 'X-AI-Token': CONFIG.AI_TOKEN },
        body: JSON.stringify({ healthcheck: true }),
      });
      setStatus(res.status < 500 ? 'online' : 'error');
    } catch (_) {
      setStatus('error');
    }
  }

  // ─────────────────────────────────────────────────────────────────────────
  // AUTO-RESIZE TEXTAREA
  // ─────────────────────────────────────────────────────────────────────────
  function autoResize(el) {
    el.style.height = 'auto';
    el.style.height = Math.min(el.scrollHeight, 90) + 'px';
  }

  // ─────────────────────────────────────────────────────────────────────────
  // KEYBOARD
  // ─────────────────────────────────────────────────────────────────────────
  function bindKeyboard() {
    document.addEventListener('keydown', e => {
      if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'A') {
        e.preventDefault();
        toggleWidget();
        return;
      }
      if (e.key === 'Escape' && isOpen) closeWidget();
    });
  }

  // ─────────────────────────────────────────────────────────────────────────
  // INIT
  // ─────────────────────────────────────────────────────────────────────────
  async function init() {
    const { fab, widget } = buildHTML();

    $fab       = fab;
    $widget    = widget;
    $chat      = widget.querySelector('#n8n-ai-chat');
    $textarea  = widget.querySelector('#n8n-ai-textarea');
    $send      = widget.querySelector('#n8n-ai-send');
    $statusDot = widget.querySelector('#n8n-ai-sdot');

    await restorePosition();

    addMessage('ai',
      'Describe el workflow que necesitas y lo creo por ti.\n' +
      'Los workflows se crean inactivos — revísalos antes de activar.'
    );

    bindDrag(widget.querySelector('#n8n-ai-header'));

    $fab.addEventListener('click', openWidget);
    widget.querySelector('#n8n-ai-minimize').addEventListener('click', closeWidget);
    widget.querySelector('#n8n-ai-close').addEventListener('click', closeWidget);

    $send.addEventListener('click', sendMessage);
    $textarea.addEventListener('keydown', e => {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
    });
    $textarea.addEventListener('input', () => autoResize($textarea));

    bindKeyboard();

    $fab.style.display = 'flex';
    checkHealth();
  }

  // ─────────────────────────────────────────────────────────────────────────
  // BOOT
  // ─────────────────────────────────────────────────────────────────────────
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

})();
